WITH seed("key", en, zh, hi, es, ca, ar, fr, de, pt, ru, it) AS (
  VALUES
    ('auth.common.verify_email_required', 'Please verify your email before accessing the builder. Check your inbox for the confirmation link.', '请在访问编辑器前验证您的电子邮件。请检查收件箱中的确认链接。', 'बिल्डर में जाने से पहले कृपया अपना ईमेल सत्यापित करें। पुष्टि लिंक के लिए अपना इनबॉक्स देखें।', 'Verifica tu correo antes de acceder al editor. Revisa tu bandeja de entrada para el enlace de confirmacion.', 'Verifica el teu correu abans d''accedir al builder. Revisa la safata d''entrada per a l''enllac de confirmacio.', 'يرجى التحقق من بريدك الإلكتروني قبل الدخول إلى المنشئ. تحقق من صندوق الوارد لرابط التأكيد.', 'Veuillez verifier votre e-mail avant d''acceder au builder. Verifiez votre boite de reception pour le lien de confirmation.', 'Bitte bestaetige deine E-Mail, bevor du auf den Builder zugreifst. Pruefe deinen Posteingang auf den Bestaetigungslink.', 'Verifique seu e-mail antes de acessar o builder. Confira sua caixa de entrada para o link de confirmacao.', 'Пожалуйста, подтвердите e-mail перед входом в конструктор. Проверьте входящие для ссылки подтверждения.', 'Verifica la tua email prima di accedere al builder. Controlla la posta in arrivo per il link di conferma.'),

    ('auth.common.email_invalid', 'Please enter a valid email address.', '请输入有效的电子邮件地址。', 'कृपया एक मान्य ईमेल पता दर्ज करें।', 'Introduce una direccion de correo valida.', 'Introdueix una adreca de correu valida.', 'يرجى إدخال عنوان بريد إلكتروني صالح.', 'Veuillez saisir une adresse e-mail valide.', 'Bitte gib eine gueltige E-Mail-Adresse ein.', 'Digite um endereco de e-mail valido.', 'Введите корректный адрес e-mail.', 'Inserisci un indirizzo email valido.'),
    ('auth.common.password_min_length', 'Password must be at least 8 characters long.', '密码长度至少为8个字符。', 'पासवर्ड कम से कम 8 अक्षरों का होना चाहिए।', 'La contrasena debe tener al menos 8 caracteres.', 'La contrasenya ha de tenir almenys 8 caracters.', 'يجب أن تتكون كلمة المرور من 8 أحرف على الأقل.', 'Le mot de passe doit contenir au moins 8 caracteres.', 'Das Passwort muss mindestens 8 Zeichen lang sein.', 'A senha deve ter pelo menos 8 caracteres.', 'Пароль должен содержать не менее 8 символов.', 'La password deve contenere almeno 8 caratteri.'),
