    ('auth.error.page_title', 'Authentication Error | WeddWeb', '身份验证错误 | WeddWeb', 'प्रमाणीकरण त्रुटि | WeddWeb', 'Error de autenticacion | WeddWeb', 'Error d''autenticacio | WeddWeb', 'خطأ في المصادقة | WeddWeb', 'Erreur d''authentification | WeddWeb', 'Authentifizierungsfehler | WeddWeb', 'Erro de autenticacao | WeddWeb', 'Ошибка аутентификации | WeddWeb', 'Errore di autenticazione | WeddWeb'),
    ('auth.error.title', 'Authentication Error', '身份验证错误', 'प्रमाणीकरण त्रुटि', 'Error de autenticacion', 'Error d''autenticacio', 'خطأ في المصادقة', 'Erreur d''authentification', 'Authentifizierungsfehler', 'Erro de autenticacao', 'Ошибка аутентификации', 'Errore di autenticazione'),
    ('auth.error.message', 'We could not complete your authentication. This could be due to an expired link or invalid code.', '我们无法完成身份验证。可能是链接已过期或代码无效。', 'हम प्रमाणीकरण पूरा नहीं कर सके। यह लिंक समाप्त होने या अमान्य कोड के कारण हो सकता है।', 'No pudimos completar tu autenticacion. Puede deberse a un enlace caducado o codigo invalido.', 'No hem pogut completar la teva autenticacio. Pot ser per un enllac caducat o un codi invalid.', 'لم نتمكن من إكمال المصادقة. قد يكون السبب رابط منتهي الصلاحية أو رمز غير صالح.', 'Nous n''avons pas pu terminer votre authentification. Cela peut etre du a un lien expire ou un code invalide.', 'Deine Authentifizierung konnte nicht abgeschlossen werden. Der Link ist moeglicherweise abgelaufen oder der Code ungueltig.', 'Nao foi possivel concluir sua autenticacao. Isso pode ocorrer por link expirado ou codigo invalido.', 'Не удалось завершить аутентификацию. Возможно, ссылка истекла или код недействителен.', 'Non siamo riusciti a completare l''autenticazione. Il link potrebbe essere scaduto o il codice non valido.')
),
expanded AS (
  SELECT "key", 'en'::text AS locale, en AS value FROM seed
  UNION ALL SELECT "key", 'zh', zh FROM seed
  UNION ALL SELECT "key", 'hi', hi FROM seed
  UNION ALL SELECT "key", 'es', es FROM seed
  UNION ALL SELECT "key", 'ca', ca FROM seed
  UNION ALL SELECT "key", 'ar', ar FROM seed
  UNION ALL SELECT "key", 'fr', fr FROM seed
  UNION ALL SELECT "key", 'de', de FROM seed
  UNION ALL SELECT "key", 'pt', pt FROM seed
  UNION ALL SELECT "key", 'ru', ru FROM seed
  UNION ALL SELECT "key", 'it', it FROM seed
)
INSERT INTO public.global_translations ("key", locale, value)
SELECT "key", locale, value
FROM expanded
ON CONFLICT ("key", locale)
DO UPDATE SET value = EXCLUDED.value;

COMMIT;
